import{_ as s,o as n,c as e,ag as p}from"./chunks/framework.BDReElpY.js";const q=JSON.parse('{"title":"Policy System","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/policy.md","filePath":"archive/reference/policy.md"}'),t={name:"archive/reference/policy.md"};function i(l,a,o,c,d,u){return n(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="policy-system" tabindex="-1">Policy System <a class="header-anchor" href="#policy-system" aria-label="Permalink to &quot;Policy System&quot;">​</a></h1><p><strong>Version:</strong> 0.2.0 <strong>Last Updated:</strong> November 2025</p><p>This document describes Vex&#39;s policy system, which provides metadata annotations for structs and fields, enabling features like serialization, validation, and code generation.</p><hr><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ol><li><a href="#overview">Overview</a></li><li><a href="#policy-declarations">Policy Declarations</a></li><li><a href="#policy-composition">Policy Composition</a></li><li><a href="#struct-application">Struct Application</a></li><li><a href="#metadata-resolution">Metadata Resolution</a></li><li><a href="#inline-metadata">Inline Metadata</a></li><li><a href="#use-cases">Use Cases</a></li><li><a href="#examples">Examples</a></li></ol><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The policy system allows you to define reusable metadata templates that can be applied to structs and their fields. This enables:</p><ul><li><strong>Serialization</strong>: JSON, XML, database mappings</li><li><strong>Validation</strong>: Field constraints and rules</li><li><strong>Code Generation</strong>: Automatic CRUD operations, API endpoints</li><li><strong>Documentation</strong>: Field descriptions and examples</li><li><strong>UI Generation</strong>: Form layouts and input types</li></ul><h3 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h3><ul><li><strong>Policy</strong>: A named collection of field metadata</li><li><strong>Metadata</strong>: Key-value annotations using backtick syntax</li><li><strong>Composition</strong>: Policies can inherit from parent policies</li><li><strong>Application</strong>: Structs apply policies using <code>with</code> clause</li><li><strong>Resolution</strong>: Metadata is merged with precedence rules</li></ul><hr><h2 id="policy-declarations" tabindex="-1">Policy Declarations <a class="header-anchor" href="#policy-declarations" aria-label="Permalink to &quot;Policy Declarations&quot;">​</a></h2><h3 id="basic-policy-syntax" tabindex="-1">Basic Policy Syntax <a class="header-anchor" href="#basic-policy-syntax" aria-label="Permalink to &quot;Basic Policy Syntax&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy PolicyName {</span></span>
<span class="line"><span>    field_name \`key:&quot;value&quot;\`,</span></span>
<span class="line"><span>    another_field \`type:&quot;string&quot; required:&quot;true&quot;\`</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Components:</strong></p><ul><li><code>policy</code> keyword</li><li>Policy name (identifier)</li><li>Field declarations with metadata in backticks</li><li>Comma-separated fields</li></ul><h3 id="metadata-syntax" tabindex="-1">Metadata Syntax <a class="header-anchor" href="#metadata-syntax" aria-label="Permalink to &quot;Metadata Syntax&quot;">​</a></h3><p>Metadata uses a simple key-value format within backticks:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>\`key1:&quot;value1&quot; key2:&quot;value2&quot; key3:&quot;true&quot;\`</span></span></code></pre></div><p><strong>Rules:</strong></p><ul><li>Keys and values are strings</li><li>Multiple key-value pairs separated by spaces</li><li>Values can contain special characters</li><li>No nested structures (flat key-value pairs)</li></ul><h3 id="example-policies" tabindex="-1">Example Policies <a class="header-anchor" href="#example-policies" aria-label="Permalink to &quot;Example Policies&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy APIModel {</span></span>
<span class="line"><span>    id \`json:&quot;id&quot; db:&quot;id&quot; required:&quot;true&quot;\`,</span></span>
<span class="line"><span>    name \`json:&quot;name&quot; db:&quot;name&quot; max_length:&quot;100&quot;\`,</span></span>
<span class="line"><span>    email \`json:&quot;email&quot; db:&quot;email&quot; format:&quot;email&quot;\`,</span></span>
<span class="line"><span>    created_at \`json:&quot;created_at&quot; db:&quot;created_at&quot; type:&quot;datetime&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>policy ValidationRules {</span></span>
<span class="line"><span>    age \`min:&quot;0&quot; max:&quot;150&quot;\`,</span></span>
<span class="line"><span>    salary \`min:&quot;0&quot;\`,</span></span>
<span class="line"><span>    phone \`pattern:&quot;^\\\\+?[1-9]\\\\d{1,14}$&quot;\`</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="policy-composition" tabindex="-1">Policy Composition <a class="header-anchor" href="#policy-composition" aria-label="Permalink to &quot;Policy Composition&quot;">​</a></h2><h3 id="parent-policies" tabindex="-1">Parent Policies <a class="header-anchor" href="#parent-policies" aria-label="Permalink to &quot;Parent Policies&quot;">​</a></h3><p>Policies can inherit metadata from parent policies:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy BaseModel {</span></span>
<span class="line"><span>    id \`db:&quot;id&quot; indexed:&quot;true&quot;\`,</span></span>
<span class="line"><span>    created_at \`db:&quot;created_at&quot;\`,</span></span>
<span class="line"><span>    updated_at \`db:&quot;updated_at&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>policy APIModel with BaseModel {</span></span>
<span class="line"><span>    id \`json:&quot;id&quot;\`,  // Overrides db:&quot;id&quot; with json:&quot;id&quot;</span></span>
<span class="line"><span>    name \`json:&quot;name&quot;\`,</span></span>
<span class="line"><span>    email \`json:&quot;email&quot;\`</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Inheritance Rules:</strong></p><ol><li>Child policies inherit all fields from parent policies</li><li>Child field metadata overrides parent metadata for the same field</li><li>Multiple inheritance is supported with comma separation</li></ol><h3 id="multiple-inheritance" tabindex="-1">Multiple Inheritance <a class="header-anchor" href="#multiple-inheritance" aria-label="Permalink to &quot;Multiple Inheritance&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy Timestamped {</span></span>
<span class="line"><span>    created_at \`db:&quot;created_at&quot;\`,</span></span>
<span class="line"><span>    updated_at \`db:&quot;updated_at&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>policy SoftDelete {</span></span>
<span class="line"><span>    deleted_at \`db:&quot;deleted_at&quot;\`,</span></span>
<span class="line"><span>    is_deleted \`db:&quot;is_deleted&quot; default:&quot;false&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>policy FullModel with Timestamped, SoftDelete {</span></span>
<span class="line"><span>    id \`json:&quot;id&quot; db:&quot;id&quot;\`,</span></span>
<span class="line"><span>    name \`json:&quot;name&quot; db:&quot;name&quot;\`</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Resolution Order:</strong></p><ol><li>First parent policies processed left-to-right</li><li>Child policy fields override parent fields</li><li>Later parents can override earlier parents</li></ol><hr><h2 id="struct-application" tabindex="-1">Struct Application <a class="header-anchor" href="#struct-application" aria-label="Permalink to &quot;Struct Application&quot;">​</a></h2><h3 id="basic-application" tabindex="-1">Basic Application <a class="header-anchor" href="#basic-application" aria-label="Permalink to &quot;Basic Application&quot;">​</a></h3><p>Apply policies to structs using the <code>with</code> clause:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct User with APIModel {</span></span>
<span class="line"><span>    id: i32,</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    email: string,</span></span>
<span class="line"><span>    created_at: i64,</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>struct Product with APIModel, ValidationRules {</span></span>
<span class="line"><span>    id: i32,</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    price: f64,</span></span>
<span class="line"><span>    category: string,</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Effects:</strong></p><ul><li>All policy fields must exist in the struct</li><li>Metadata is applied to matching fields</li><li>Struct gains the combined metadata from all policies</li></ul><h3 id="field-requirements" tabindex="-1">Field Requirements <a class="header-anchor" href="#field-requirements" aria-label="Permalink to &quot;Field Requirements&quot;">​</a></h3><p>When a policy is applied, the struct must contain all fields defined in the policy:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy RequiredFields {</span></span>
<span class="line"><span>    id \`required:&quot;true&quot;\`,</span></span>
<span class="line"><span>    name \`required:&quot;true&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// ✅ Valid - has both required fields</span></span>
<span class="line"><span>struct User with RequiredFields {</span></span>
<span class="line"><span>    id: i32,</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    email: string,  // Extra fields allowed</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// ❌ Invalid - missing &#39;name&#39; field</span></span>
<span class="line"><span>struct Incomplete with RequiredFields {</span></span>
<span class="line"><span>    id: i32,</span></span>
<span class="line"><span>    // name field missing</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="metadata-resolution" tabindex="-1">Metadata Resolution <a class="header-anchor" href="#metadata-resolution" aria-label="Permalink to &quot;Metadata Resolution&quot;">​</a></h2><h3 id="merge-order" tabindex="-1">Merge Order <a class="header-anchor" href="#merge-order" aria-label="Permalink to &quot;Merge Order&quot;">​</a></h3><p>When multiple sources define metadata for the same field, they are merged with this precedence:</p><ol><li><strong>Inline metadata</strong> (highest precedence)</li><li><strong>Child policy metadata</strong></li><li><strong>Parent policy metadata</strong> (lowest precedence)</li></ol><h3 id="example-resolution" tabindex="-1">Example Resolution <a class="header-anchor" href="#example-resolution" aria-label="Permalink to &quot;Example Resolution&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy Base {</span></span>
<span class="line"><span>    id \`db:&quot;id&quot;\`,</span></span>
<span class="line"><span>    name \`db:&quot;name&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>policy API with Base {</span></span>
<span class="line"><span>    id \`json:&quot;id&quot;\`,     // Overrides db:&quot;id&quot;</span></span>
<span class="line"><span>    name \`json:&quot;name&quot;\`  // Overrides db:&quot;name&quot;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>struct User with API {</span></span>
<span class="line"><span>    id: i32 \`primary_key:&quot;true&quot;\`,  // Overrides json:&quot;id&quot;</span></span>
<span class="line"><span>    name: string,                  // Uses json:&quot;name&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Final metadata for <code>id</code> field:</strong></p><ul><li><code>primary_key:&quot;true&quot;</code> (from inline)</li><li><code>json:&quot;id&quot;</code> (from API policy, but overridden by inline)</li></ul><p><strong>Final metadata for <code>name</code> field:</strong></p><ul><li><code>json:&quot;name&quot;</code> (from API policy)</li></ul><hr><h2 id="inline-metadata" tabindex="-1">Inline Metadata <a class="header-anchor" href="#inline-metadata" aria-label="Permalink to &quot;Inline Metadata&quot;">​</a></h2><h3 id="field-level-metadata" tabindex="-1">Field-Level Metadata <a class="header-anchor" href="#field-level-metadata" aria-label="Permalink to &quot;Field-Level Metadata&quot;">​</a></h3><p>You can add metadata directly to struct fields:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct User with APIModel {</span></span>
<span class="line"><span>    id: i32 \`primary_key:&quot;true&quot; auto_increment:&quot;true&quot;\`,</span></span>
<span class="line"><span>    name: string \`max_length:&quot;100&quot;\`,</span></span>
<span class="line"><span>    email: string \`unique:&quot;true&quot;\`,</span></span>
<span class="line"><span>    created_at: i64 \`default:&quot;now()&quot;\`,</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Use Cases:</strong></p><ul><li>Field-specific overrides</li><li>Additional constraints not in policies</li><li>Database-specific annotations</li><li>Validation rules</li></ul><h3 id="metadata-combination" tabindex="-1">Metadata Combination <a class="header-anchor" href="#metadata-combination" aria-label="Permalink to &quot;Metadata Combination&quot;">​</a></h3><p>Inline metadata is merged with policy metadata:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy APIModel {</span></span>
<span class="line"><span>    id \`json:&quot;id&quot;\`,</span></span>
<span class="line"><span>    name \`json:&quot;name&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>struct User with APIModel {</span></span>
<span class="line"><span>    id: i32 \`db:&quot;user_id&quot; primary_key:&quot;true&quot;\`,  // Combines with json:&quot;id&quot;</span></span>
<span class="line"><span>    name: string \`max_length:&quot;50&quot;\`,             // Adds to json:&quot;name&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Result for <code>id</code>:</strong></p><ul><li><code>json:&quot;id&quot;</code> (from policy)</li><li><code>db:&quot;user_id&quot;</code> (from inline)</li><li><code>primary_key:&quot;true&quot;</code> (from inline)</li></ul><hr><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><h3 id="_1-api-serialization" tabindex="-1">1. API Serialization <a class="header-anchor" href="#_1-api-serialization" aria-label="Permalink to &quot;1. API Serialization&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy JSONAPI {</span></span>
<span class="line"><span>    id \`json:&quot;id&quot;\`,</span></span>
<span class="line"><span>    name \`json:&quot;name&quot;\`,</span></span>
<span class="line"><span>    email \`json:&quot;email&quot;\`,</span></span>
<span class="line"><span>    created_at \`json:&quot;created_at&quot;\`,</span></span>
<span class="line"><span>    updated_at \`json:&quot;updated_at&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>struct User with JSONAPI {</span></span>
<span class="line"><span>    id: i32,</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    email: string,</span></span>
<span class="line"><span>    created_at: i64,</span></span>
<span class="line"><span>    updated_at: i64,</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_2-database-mapping" tabindex="-1">2. Database Mapping <a class="header-anchor" href="#_2-database-mapping" aria-label="Permalink to &quot;2. Database Mapping&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy DatabaseModel {</span></span>
<span class="line"><span>    id \`db:&quot;id&quot; type:&quot;INTEGER&quot; primary_key:&quot;true&quot;\`,</span></span>
<span class="line"><span>    name \`db:&quot;name&quot; type:&quot;VARCHAR(100)&quot; not_null:&quot;true&quot;\`,</span></span>
<span class="line"><span>    email \`db:&quot;email&quot; type:&quot;VARCHAR(255)&quot; unique:&quot;true&quot;\`,</span></span>
<span class="line"><span>    created_at \`db:&quot;created_at&quot; type:&quot;TIMESTAMP&quot; default:&quot;CURRENT_TIMESTAMP&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>struct User with DatabaseModel {</span></span>
<span class="line"><span>    id: i32,</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    email: string,</span></span>
<span class="line"><span>    created_at: i64,</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_3-validation-rules" tabindex="-1">3. Validation Rules <a class="header-anchor" href="#_3-validation-rules" aria-label="Permalink to &quot;3. Validation Rules&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy Validation {</span></span>
<span class="line"><span>    age \`min:&quot;0&quot; max:&quot;150&quot;\`,</span></span>
<span class="line"><span>    email \`format:&quot;email&quot; required:&quot;true&quot;\`,</span></span>
<span class="line"><span>    phone \`pattern:&quot;^\\\\+?[1-9]\\\\d{1,14}$&quot;\`,</span></span>
<span class="line"><span>    salary \`min:&quot;0&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>struct Employee with Validation {</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    age: i32,</span></span>
<span class="line"><span>    email: string,</span></span>
<span class="line"><span>    phone: string,</span></span>
<span class="line"><span>    salary: f64,</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_4-ui-generation" tabindex="-1">4. UI Generation <a class="header-anchor" href="#_4-ui-generation" aria-label="Permalink to &quot;4. UI Generation&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy FormUI {</span></span>
<span class="line"><span>    name \`ui:&quot;text&quot; label:&quot;Full Name&quot; required:&quot;true&quot;\`,</span></span>
<span class="line"><span>    email \`ui:&quot;email&quot; label:&quot;Email Address&quot; required:&quot;true&quot;\`,</span></span>
<span class="line"><span>    age \`ui:&quot;number&quot; label:&quot;Age&quot; min:&quot;0&quot; max:&quot;150&quot;\`,</span></span>
<span class="line"><span>    department \`ui:&quot;select&quot; label:&quot;Department&quot; options:&quot;Engineering,Sales,Marketing&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>struct Employee with FormUI {</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    email: string,</span></span>
<span class="line"><span>    age: i32,</span></span>
<span class="line"><span>    department: string,</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_5-multi-format-support" tabindex="-1">5. Multi-Format Support <a class="header-anchor" href="#_5-multi-format-support" aria-label="Permalink to &quot;5. Multi-Format Support&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy MultiFormat {</span></span>
<span class="line"><span>    id \`json:&quot;id&quot; xml:&quot;id&quot; db:&quot;id&quot;\`,</span></span>
<span class="line"><span>    name \`json:&quot;name&quot; xml:&quot;name&quot; db:&quot;name&quot;\`,</span></span>
<span class="line"><span>    data \`json:&quot;data&quot; xml:&quot;data&quot; db:&quot;data&quot; type:&quot;JSONB&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>struct Document with MultiFormat {</span></span>
<span class="line"><span>    id: i32,</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    data: string,  // JSON string</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><h3 id="complete-api-model" tabindex="-1">Complete API Model <a class="header-anchor" href="#complete-api-model" aria-label="Permalink to &quot;Complete API Model&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Base model with common fields</span></span>
<span class="line"><span>policy BaseModel {</span></span>
<span class="line"><span>    id \`json:&quot;id&quot; db:&quot;id&quot; type:&quot;INTEGER&quot; primary_key:&quot;true&quot;\`,</span></span>
<span class="line"><span>    created_at \`json:&quot;created_at&quot; db:&quot;created_at&quot; type:&quot;TIMESTAMP&quot;\`,</span></span>
<span class="line"><span>    updated_at \`json:&quot;updated_at&quot; db:&quot;updated_at&quot; type:&quot;TIMESTAMP&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// API-specific extensions</span></span>
<span class="line"><span>policy APIModel with BaseModel {</span></span>
<span class="line"><span>    id \`xml:&quot;id&quot;\`,  // Add XML support</span></span>
<span class="line"><span>    name \`json:&quot;name&quot; xml:&quot;name&quot; db:&quot;name&quot; required:&quot;true&quot;\`,</span></span>
<span class="line"><span>    email \`json:&quot;email&quot; xml:&quot;email&quot; db:&quot;email&quot; format:&quot;email&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Validation rules</span></span>
<span class="line"><span>policy UserValidation {</span></span>
<span class="line"><span>    name \`min_length:&quot;2&quot; max_length:&quot;100&quot;\`,</span></span>
<span class="line"><span>    email \`format:&quot;email&quot; unique:&quot;true&quot;\`,</span></span>
<span class="line"><span>    age \`min:&quot;13&quot; max:&quot;150&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Complete user model</span></span>
<span class="line"><span>struct User with APIModel, UserValidation {</span></span>
<span class="line"><span>    id: i32,</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    email: string,</span></span>
<span class="line"><span>    age: i32 \`json:&quot;age&quot; db:&quot;age&quot;\`,  // Additional inline metadata</span></span>
<span class="line"><span>    created_at: i64,</span></span>
<span class="line"><span>    updated_at: i64,</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn main(): i32 {</span></span>
<span class="line"><span>    let user = User {</span></span>
<span class="line"><span>        id: 1,</span></span>
<span class="line"><span>        name: &quot;Alice Johnson&quot;,</span></span>
<span class="line"><span>        email: &quot;alice@example.com&quot;,</span></span>
<span class="line"><span>        age: 30,</span></span>
<span class="line"><span>        created_at: 1699000000,</span></span>
<span class="line"><span>        updated_at: 1699000000,</span></span>
<span class="line"><span>    };</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // At compile time, the metadata is available for:</span></span>
<span class="line"><span>    // - JSON serialization/deserialization</span></span>
<span class="line"><span>    // - Database ORM operations</span></span>
<span class="line"><span>    // - API documentation generation</span></span>
<span class="line"><span>    // - Form validation</span></span>
<span class="line"><span>    // - UI component generation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    return 0;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="policy-inheritance-chain" tabindex="-1">Policy Inheritance Chain <a class="header-anchor" href="#policy-inheritance-chain" aria-label="Permalink to &quot;Policy Inheritance Chain&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Foundation policies</span></span>
<span class="line"><span>policy Identifiable {</span></span>
<span class="line"><span>    id \`type:&quot;uuid&quot; required:&quot;true&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>policy Timestamped with Identifiable {</span></span>
<span class="line"><span>    created_at \`type:&quot;datetime&quot;\`,</span></span>
<span class="line"><span>    updated_at \`type:&quot;datetime&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>policy SoftDelete with Timestamped {</span></span>
<span class="line"><span>    deleted_at \`type:&quot;datetime&quot;\`,</span></span>
<span class="line"><span>    is_deleted \`type:&quot;boolean&quot; default:&quot;false&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Domain policies</span></span>
<span class="line"><span>policy APIModel with SoftDelete {</span></span>
<span class="line"><span>    id \`json:&quot;id&quot;\`,</span></span>
<span class="line"><span>    name \`json:&quot;name&quot;\`,</span></span>
<span class="line"><span>    description \`json:&quot;description&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>policy DatabaseModel with SoftDelete {</span></span>
<span class="line"><span>    id \`db:&quot;id&quot; primary_key:&quot;true&quot;\`,</span></span>
<span class="line"><span>    name \`db:&quot;name&quot; not_null:&quot;true&quot;\`,</span></span>
<span class="line"><span>    description \`db:&quot;description&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Concrete usage</span></span>
<span class="line"><span>struct Product with APIModel, DatabaseModel {</span></span>
<span class="line"><span>    id: string,</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    description: string,</span></span>
<span class="line"><span>    created_at: i64,</span></span>
<span class="line"><span>    updated_at: i64,</span></span>
<span class="line"><span>    deleted_at: i64,</span></span>
<span class="line"><span>    is_deleted: bool,</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="metadata-driven-code-generation" tabindex="-1">Metadata-Driven Code Generation <a class="header-anchor" href="#metadata-driven-code-generation" aria-label="Permalink to &quot;Metadata-Driven Code Generation&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>policy CRUD {</span></span>
<span class="line"><span>    id \`primary_key:&quot;true&quot; auto_increment:&quot;true&quot;\`,</span></span>
<span class="line"><span>    name \`unique:&quot;true&quot; index:&quot;name_idx&quot;\`,</span></span>
<span class="line"><span>    created_at \`default:&quot;CURRENT_TIMESTAMP&quot;\`,</span></span>
<span class="line"><span>    updated_at \`on_update:&quot;CURRENT_TIMESTAMP&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>policy APIEndpoints {</span></span>
<span class="line"><span>    id \`route:&quot;/api/{id}&quot; methods:&quot;GET,PUT,DELETE&quot;\`,</span></span>
<span class="line"><span>    name \`route:&quot;/api/search&quot; methods:&quot;GET&quot; query:&quot;name&quot;\`</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>struct User with CRUD, APIEndpoints {</span></span>
<span class="line"><span>    id: i32,</span></span>
<span class="line"><span>    name: string,</span></span>
<span class="line"><span>    email: string,</span></span>
<span class="line"><span>    created_at: i64,</span></span>
<span class="line"><span>    updated_at: i64,</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// This could generate:</span></span>
<span class="line"><span>// 1. Database table creation</span></span>
<span class="line"><span>// 2. CRUD repository methods</span></span>
<span class="line"><span>// 3. REST API endpoints</span></span>
<span class="line"><span>// 4. OpenAPI documentation</span></span>
<span class="line"><span>// 5. Frontend forms and components</span></span></code></pre></div><hr><p><strong>Previous</strong>: <a href="./19_Package_Manager">19_Package_Manager.md</a></p><p><strong>Maintained by</strong>: Vex Language Team</p>`,92)])])}const h=s(t,[["render",i]]);export{q as __pageData,h as default};
